    mu[1] = 1;
    let mut is_prime = vec![true; n + 1];

    for i in 2..=n {
        if is_prime[i] {
            let mut j = i;
            while j <= n {
                if j != i { is_prime[j] = false; }
                mu[j] = -mu[j];
                j += i;
            }
            let i2 = i * i;
            let mut j = i2;
            while j <= n {
                mu[j] = 0;
                j += i2;
            }
        }
    }
    mu[1..].iter().sum()
